1	import { readFileSync, mkdirSync, existsSync } from "node:fs";
2	import { join, dirname, resolve } from "node:path";
3	import { fileURLToPath } from "node:url";
4	import { parse as parseYaml } from "yaml";
5	import type { Page } from "@playwright/test";
6	
7	const __dirname = dirname(fileURLToPath(import.meta.url));
8	
9	// -- Config ---------------------------------------------------------------
10	let _configPath: string | null = null;
11	let _config: E2EConfig | null = null;
12	
13	function findConfigPath(): string {
14	  const envPath = process.env.E2E_CONFIG_PATH;
15	  if (envPath && existsSync(envPath)) return resolve(envPath);
16	
17	  let dir = __dirname;
18	  for (let i = 0; i < 10; i++) {
19	    const candidate = resolve(dir, "config.yaml");
20	    if (existsSync(candidate)) return candidate;
21	    const parent = resolve(dir, "..");
22	    if (parent === dir) break;
23	    dir = parent;
24	  }
25	  return "";
26	}
27	
28	const SCREENSHOTS_DIR = join(__dirname, "results", "screenshots");
29	
30	interface E2EConfig {
31	  baseUrl?: string;
32	  timeout?: number | string;
33	}
34	
35	function getConfig(): E2EConfig {
36	  if (_config) return _config;
37	  _configPath = findConfigPath();
38	  if (!_configPath) return {};
39	  const raw = parseYaml(readFileSync(_configPath, "utf-8"));
40	  if (typeof raw !== "object" || raw === null) {
41	    throw new Error(`Invalid config.yaml: expected object, got ${typeof raw}`);
42	  }
43	  _config = raw as E2EConfig;
44	  return _config;
45	}
46	
47	export function baseUrl(): string {
48	  return getConfig().baseUrl ?? "http://localhost:8081";
49	}
50	export function timeout(): number {
51	  return Number(getConfig().timeout ?? 30000);
52	}
53	
54	// -- Evidence ---------------------------------------------------------------
55	export async function screenshot(page: Page, tcId: string): Promise<string> {
56	  if (!existsSync(SCREENSHOTS_DIR))
57	    mkdirSync(SCREENSHOTS_DIR, { recursive: true });
58	  const path = join(SCREENSHOTS_DIR, `${tcId}.png`);
59	  await page.screenshot({ path, fullPage: true });
60	  return path;
61	}
62	
63	// -- Retry ------------------------------------------------------------------
64	export async function withRetry<T>(
65	  fn: () => Promise<T>,
66	  opts?: { maxRetries?: number; delayMs?: number; label?: string },
67	): Promise<T> {
68	  const maxRetries = opts?.maxRetries ?? 3;
69	  const delayMs = opts?.delayMs ?? 1000;
70	  const label = opts?.label ?? "operation";
71	
72	  for (let attempt = 1; attempt <= maxRetries; attempt++) {
73	    try {
74	      return await fn();
75	    } catch (e) {
76	      if (attempt === maxRetries) throw e;
77	      console.warn(
78	        `${label} failed (attempt ${attempt}/${maxRetries}), retrying in ${delayMs}ms...`,
79	        e,
80	      );
81	      await new Promise((resolve) => setTimeout(resolve, delayMs));
82	    }
83	  }
84	  throw new Error("unreachable");
85	}
86	
87	// -- File helpers ------------------------------------------------------------
88	export const PROJECT_ROOT = resolve(__dirname, "..", "..");
89	
90	export function readProjectFile(relPath: string): string {
91	  return readFileSync(join(PROJECT_ROOT, relPath), "utf-8");
92	}
93	
94	export function projectFileExists(relPath: string): boolean {
95	  return existsSync(join(PROJECT_ROOT, relPath));
96	}
